input.command:
# Phase 1: Update secret with bundled CA (old+new) + OLD leaf cert
# This establishes mutual trust between pods before we swap the leaf cert
kubectl patch secret es-http-tls -n elasticsearch --type='json' -p="[
  {\"op\":\"replace\",\"path\":\"/data/ca.crt\",\"value\":\"${BUNDLED_CA_B64}\"}
]"
echo "Phase 1: Secret updated with bundled CA (old+new)"

